### Шаг 2: Создание компонента Checkbox

Создадим новую папку для нашего компонента (например, `Checkbox`) и создадим три файла: `Checkbox.tsx`, `Checkbox.module.css` и `index.ts`.

#### `Checkbox.tsx`

```tsx
import React, { useState } from 'react';
import styles from './Checkbox.module.css';

interface CheckboxProps {
  label?: string;
  checked?: boolean;
  onChange?: (checked: boolean) => void;
}

const Checkbox: React.FC<CheckboxProps> = ({ label, checked = false, onChange }) => {
  const [isChecked, setIsChecked] = useState(checked);

  const handleChange = () => {
    const newChecked = !isChecked;
    setIsChecked(newChecked);
    if (onChange) {
      onChange(newChecked);
    }
  };

  return (
    <label className={styles.checkboxContainer}>
      <input
        type="checkbox"
        checked={isChecked}
        onChange={handleChange}
        className={styles.hiddenCheckbox}
      />
      <div className={styles.customCheckbox}>
        {isChecked && <div className={styles.checkmark}>✓</div>}
      </div>
      {label && <span className={styles.label}>{label}</span>}
    </label>
  );
};

export default Checkbox;
```

