### Шаг 2: Создание MobX Store

Создайте папку `stores` и файл `UserStore.ts`.

#### `stores/UserStore.ts`

```typescript
import { makeAutoObservable } from 'mobx';
import { createContext, useContext } from 'react';

interface Award {
  id: number;
  title: string;
}

class UserStore {
  awards: Award[] = [];
  isLoading: boolean = false;
  error: string | null = null;

  constructor() {
    makeAutoObservable(this);
  }

  async fetchAwards() {
    this.isLoading = true;
    this.error = null;

    try {
      const response = await fetch('/api/v1/awards');
      if (!response.ok) {
        throw new Error('Network response was not ok');
      }
      const data = await response.json();
      this.awards = data; // Предполагаем, что API возвращает массив наград
    } catch (err: any) {
      this.error = err.message;
    } finally {
      this.isLoading = false;
    }
  }
}

const userStore = new UserStore();
const UserContext = createContext(userStore);

export const useUserStore = () => useContext(UserContext);
export default UserContext;
```

### Шаг 3: Создание компонента для получения и отображения данных

Давайте создадим компонент `AwardsList`, который будет получать и отображать данные о наградах из нашего магазина.

#### `AwardsList.tsx`

```tsx
import React, { useEffect } from 'react';
import { observer } from 'mobx-react-lite';
import { useUserStore } from './stores/UserStore';

const AwardsList: React.FC = observer(() => {
  const store = useUserStore();

  useEffect(() => {
    store.fetchAwards();
  }, [store]);

  if (store.isLoading) {
    return <div>Loading...</div>;
  }

  if (store.error) {
    return <div>Error: {store.error}</div>;
  }

  return (
    <div>
      <h2>Awards</h2>
      <ul>
        {store.awards.map(award => (
          <li key={award.id}>{award.title}</li>
        ))}
      </ul>
    </div>
  );
});

export default AwardsList;
```

### Шаг 4: Использование контекста в приложении

Оберните ваше приложение в контекст `UserContext`, чтобы компоненты могли получить доступ к `UserStore`.

#### `App.tsx`

```tsx
import React from 'react';
import { observer } from 'mobx-react-lite';
import AwardsList from './AwardsList';
import UserContext from './stores/UserStore';

const App: React.FC = observer(() => {
  return (
    <UserContext.Provider value={UserContext}>
      <h1>User Awards</h1>
      <AwardsList />
    </UserContext.Provider>
  );
});

export default App;
```

