### Шаги для реализации:

1. **Настройка разрешений:** Убедитесь, что ваше приложение имеет разрешение на использование микрофона. Для этого добавьте соответствующие разрешения в файл `AndroidManifest.xml`.

2. **Скрипт для распознавания речи:** Создайте C# скрипт в Unity, который будет взаимодействовать с Android API для распознавания речи.

3. **Обработка результатов:** Скрипт будет обрабатывать результаты распознавания и выводить их в консоль или использовать по вашему усмотрению.

### 1. Настройка разрешений

Убедитесь, что ваше приложение имеет разрешения на использование микрофона. Для этого добавьте следующие строки в ваш `AndroidManifest.xml`:

```xml
<uses-permission android:name="android.permission.RECORD_AUDIO" />
<uses-permission android:name="android.permission.INTERNET" />
```

Если вы используете Unity 2018 или выше, разрешения могут автоматически добавляться через `Player Settings`.

### 2. Скрипт для распознавания речи

Создайте новый C# скрипт, например, `SpeechRecognizerUnity.cs`, и вставьте следующий код:

```csharp
using UnityEngine;
using System.Collections;
using System;
using UnityEngine.UI;

public class SpeechRecognizerUnity : MonoBehaviour
{
    // UI элементы для отображения статуса и результата
    public Text statusText;
    public Text resultText;

    private AndroidJavaObject speechRecognizer;
    private AndroidJavaObject activity;
    private bool isListening = false;

    void Start()
    {
        // Проверка платформы
        if (Application.platform == RuntimePlatform.Android)
        {
            // Получение текущей активности
            using (AndroidJavaClass unityPlayer = new AndroidJavaClass("com.unity3d.player.UnityPlayer"))
            {
                activity = unityPlayer.GetStatic<AndroidJavaObject>("currentActivity");
            }

            // Инициализация распознавателя речи
            using (AndroidJavaClass recognizerClass = new AndroidJavaClass("android.speech.SpeechRecognizer"))
            {
                bool isAvailable = recognizerClass.CallStatic<bool>("isRecognitionAvailable", activity);
                if (isAvailable)
                {
                    speechRecognizer = recognizerClass.CallStatic<AndroidJavaObject>("createSpeechRecognizer", activity);
                    InitializeRecognizer();
                    statusText.text = "Готов к прослушиванию.";
                }
                else
                {
                    statusText.text = "Распознавание речи недоступно на этом устройстве.";
                }
            }
        }
        else
        {
            statusText.text = "Платформа не поддерживается.";
        }
    }

    void InitializeRecognizer()
    {
        using (AndroidJavaClass intentClass = new AndroidJavaClass("android.content.Intent"))
        {
            AndroidJavaObject intent = new AndroidJavaObject("android.content.Intent", intentClass.GetStatic<string>("ACTION_RECOGNIZE_SPEECH"));
            intent.Call<AndroidJavaObject>("putExtra", "android.speech.extra.LANGUAGE", "ru-RU");
            intent.Call<AndroidJavaObject>("putExtra", "android.speech.extra.PROMPT", "Говорите сейчас...");
            // Дополнительные настройки при необходимости
        }

        // Настройка слушателя
        using (AndroidJavaClass listenerClass = new AndroidJavaClass("com.example.unity.SpeechRecognitionListener"))
        {
            // Предполагается, что вы создали Java-класс SpeechRecognitionListener, который вызывает Unity-методы обратного вызова
            // Однако без создания сторонних плагинов это невозможно. Поэтому предлагается использовать Intent-based подход ниже.
        }
    }

    // Метод для начала прослушивания
    public void StartListening()
    {
        if (isListening)
            return;

        if (Application.platform == RuntimePlatform.Android && speechRecognizer != null)
        {
            // Создание Intent для распознавания речи
            using (AndroidJavaClass intentClass = new AndroidJavaClass("android.content.Intent"))
            {
                AndroidJavaObject intent = new AndroidJavaObject("android.content.Intent", "android.speech.action.RECOGNIZE_SPEECH");
                intent.Call<AndroidJavaObject>("putExtra", "android.speech.extra.LANGUAGE", "ru-RU");
                intent.Call<AndroidJavaObject>("putExtra", "android.speech.extra.PROMPT", "Пожалуйста, говорите сейчас...");

                // Запуск активности для распознавания речи
                activity.Call("startActivityForResult", intent, 10);
                statusText.text = "Прослушивание...";
                isListening = true;
            }
        }
    }

    // Метод для обработки результатов (должен быть вызван из активности Android)
    public void OnActivityResult(string result)
    {
        isListening = false;
        if (!string.IsNullOrEmpty(result))
        {
            resultText.text = result;
            statusText.text = "Распознавание завершено.";
        }
        else
        {
            resultText.text = "Результат не распознан.";
            statusText.text = "Распознавание не удалось.";
        }
    }

    // Обработка разрешений (опционально)
    IEnumerator RequestMicrophonePermission()
    {
        if (Application.platform == RuntimePlatform.Android)
        {
            using (AndroidJavaClass unityPlayer = new AndroidJavaClass("com.unity3d.player.UnityPlayer"))
            {
                AndroidJavaObject currentActivity = unityPlayer.GetStatic<AndroidJavaObject>("currentActivity");
                currentActivity.Call("requestPermissions", new string[] { "android.permission.RECORD_AUDIO" }, 1);
            }
            yield return null;
        }
    }

    // Обработчик нажатия кнопки (привяжите этот метод к кнопке в интерфейсе)
    public void OnStartButtonPressed()
    {
        StartCoroutine(RequestMicrophonePermission());
        StartListening();
    }
}
```

### Ограничения и дополнительные шаги

1. **Обработка результатов:** В приведенном выше коде метод `OnActivityResult` предназначен для обработки результатов распознавания речи. Однако, для того чтобы Android активность могла передать результат обратно в Unity, необходимо создать нативный плагин на Java, который будет обрабатывать `onActivityResult` и передавать данные в Unity через `UnityPlayer.UnitySendMessage`.

2. **Создание Java-плагина:** Без создания сторонних плагинов невозможно полностью обработать результат распознавания речи. Если вы не хотите использовать сторонние библиотеки, все равно потребуется создать минимальный Java-код для обработки результата распознавания и передачи его в Unity.

3. **Обработка разрешений:** В примере выше есть метод `RequestMicrophonePermission`, который запрашивает разрешение на использование микрофона. Убедитесь, что разрешение получено перед началом прослушивания.

4. **UI элементы:** В примере предполагается, что у вас есть два UI элемента типа `Text` для отображения статуса и результата распознавания. Привяжите их в инспекторе Unity к соответствующим полям `statusText` и `resultText`.

### Пример Java-кода для плагина

Чтобы полностью реализовать обработку результатов, необходимо создать Java-класс и скомпилировать его как плагин для Unity. Ниже приведен пример простого Java-класса:

```java
package com.example.unity;

import android.app.Activity;
import android.content.Intent;
import android.speech.RecognizerIntent;
import android.os.Bundle;
import java.util.ArrayList;
import com.unity3d.player.UnityPlayer;

public class SpeechRecognitionActivity extends Activity {
    private static final int SPEECH_REQUEST_CODE = 10;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        startSpeechRecognition();
    }

    private void startSpeechRecognition() {
        Intent intent = new Intent(RecognizerIntent.ACTION_RECOGNIZE_SPEECH);
        intent.putExtra(RecognizerIntent.EXTRA_LANGUAGE, "ru-RU");
        intent.putExtra(RecognizerIntent.EXTRA_PROMPT, "Пожалуйста, говорите сейчас...");
        startActivityForResult(intent, SPEECH_REQUEST_CODE);
    }

    @Override
    protected void onActivityResult(int requestCode, int resultCode, Intent data) {
        if (requestCode == SPEECH_REQUEST_CODE) {
            String recognizedText = "";
            if (resultCode == RESULT_OK && data != null) {
                ArrayList<String> results = data.getStringArrayListExtra(RecognizerIntent.EXTRA_RESULTS);
                if (results != null && results.size() > 0) {
                    recognizedText = results.get(0);
                }
            }
            // Отправка результата обратно в Unity
            UnityPlayer.UnitySendMessage("SpeechRecognizerObject", "OnActivityResult", recognizedText);
            finish();
        }
        super.onActivityResult(requestCode, resultCode, data);
    }
}
```

### Интеграция Java-плагина в Unity

1. **Сборка плагина:** Скомпилируйте Java-класс выше в JAR-файл и поместите его в папку `Assets/Plugins/Android/` вашего проекта Unity.

2. **Запуск активности распознавания:** Модифицируйте ваш C# скрипт, чтобы запускать `SpeechRecognitionActivity` вместо простого вызова `startActivityForResult`:

```csharp
public void StartListening()
{
    if (isListening)
        return;

    if (Application.platform == RuntimePlatform.Android)
    {
        using (AndroidJavaClass unityPlayer = new AndroidJavaClass("com.unity3d.player.UnityPlayer"))
        {
            AndroidJavaObject currentActivity = unityPlayer.GetStatic<AndroidJavaObject>("currentActivity");
            AndroidJavaObject intent = new AndroidJavaObject("android.content.Intent", currentActivity, new AndroidJavaClass("com.example.unity.SpeechRecognitionActivity"));
            currentActivity.Call("startActivity", intent);
            statusText.text = "Прослушивание...";
            isListening = true;
        }
    }
}
```

3. **Имя объекта Unity:** Убедитесь, что объект, к которому привязан скрипт `SpeechRecognizerUnity`, имеет имя `SpeechRecognizerObject` или измените строку в `UnitySendMessage` на реальное имя вашего объекта.

