2. **Перевод из десятичной дроби в другую систему счисления**:
Для переводе дроби, вам нужно выделить целую и дробную части и отдельно их преобразовать.

```cpp
#include <iostream>
#include <cmath>

void convertDecimalToBinary(double num) {
    int wholePart = (int)num;
    double fractionalPart = num - wholePart;

    // Целая часть
    std::cout << "Двоичное (целая часть): " << std::bitset<32>(wholePart) << ".";

    // Дробная часть
    while (fractionalPart > 0) {
        fractionalPart *= 2;
        int bit = (int)fractionalPart;
        if (bit == 1) {
            fractionalPart -= bit;
            std::cout << "1";
        } else {
            std::cout << "0";
        }
    }
    std::cout << std::endl;
}

int main() {
    convertDecimalToBinary(2.45);
    return 0;
}
```

