```cpp
#include <iostream>
#include <string>
#include <cmath>

int convertToDecimal(const std::string &number, int base) {
    int decimalValue = 0;
    for (size_t i = 0; i < number.size(); ++i) {
        decimalValue *= base;
        if (isdigit(number[i]))
            decimalValue += number[i] - '0';
        else
            decimalValue += number[i] - 'A' + 10; // для A-F
    }
    return decimalValue;
}

void convertFromDecimal(int num, int base) {
    std::string result = "";
    while (num > 0) {
        int remainder = num % base;
        result = (remainder < 10 ? char(remainder + '0') : char(remainder - 10 + 'A')) + result;
        num /= base;
    }
    std::cout << result << std::endl;
}

int main() {
    std::string number = "ABCD";
    int base = 16; // Шестнадцатеричная
    int decimalValue = convertToDecimal(number, base);

    std::cout << "Десятичное: " << decimalValue << std::endl;

    std::cout << "Двоичное: ";
    convertFromDecimal(decimalValue, 2);

    return 0;
}
```

